def min_cost(tasks):
    tasks_sorted = sorted(tasks, key=lambda x: x[1])
    end_day_to_tasks = {}
    for task in tasks_sorted:
        e = task[1]
        if e not in end_day_to_tasks:
            end_day_to_tasks[e] = []
        end_day_to_tasks[e].append(task)

    dp = [float('inf')] * 8
    dp[0] = 0

    for e in range(1, 8):
        if e in end_day_to_tasks:
            for task in end_day_to_tasks[e]:
                s, end, cost = task
                prev = s - 1
                if prev >= 0 and dp[prev] + cost < dp[e]:
                    dp[e] = dp[prev] + cost

    return dp[7] if dp[7] != float('inf') else -1
