import java.util.ArrayList;
import java.util.List;

public class MarketingCampaignScheduler {

    static class Campaign {
        String name;
        int cost;
        int expectedReturn;

        public Campaign(String name, int cost, int expectedReturn) {
            this.name = name;
            this.cost = cost;
            this.expectedReturn = expectedReturn;
        }
    }

    public static void main(String[] args) {
        List<Campaign> campaigns = new ArrayList<>();
        campaigns.add(new Campaign("SocialMediaAd", 300, 600));
        campaigns.add(new Campaign("EmailBlast", 200, 400));
        campaigns.add(new Campaign("VideoCampaign", 500, 1000));
        int budget = 700;

        int[][] dp = new int[campaigns.size() + 1][budget + 1];

        for (int i = 1; i <= campaigns.size(); i++) {
            Campaign c = campaigns.get(i - 1);
            for (int j = 0; j <= budget; j++) {
                if (c.cost > j) dp[i][j] = dp[i - 1][j];
                else dp[i][j] = Math.max(dp[i - 1][j], dp[i - 1][j - c.cost] + c.expectedReturn);
            }
        }

        int maxReturn = 0;
        int maxBudget = 0;
        for (int j = 0; j <= budget; j++) {
            if (dp[campaigns.size()][j] > maxReturn) {
                maxReturn = dp[campaigns.size()][j];
                maxBudget = j;
            }
        }

        List<Campaign> selected = new ArrayList<>();
        int currentBudget = maxBudget;
        for (int i = campaigns.size(); i > 0 && currentBudget > 0; i--) {
            if (dp[i][currentBudget] != dp[i - 1][currentBudget]) {
                Campaign c = campaigns.get(i - 1);
                selected.add(c);
                currentBudget -= c.cost;
            }
        }

        System.out.println("Maximum Return: " + maxReturn);
        System.out.println("Selected Campaigns:");
        selected.forEach(c -> System.out.println(c.name + " - Cost: " + c.cost + ", Return: " + c.expectedReturn));
    }
}
