#include <bits/stdc++.h>
using namespace std;

struct State {
    int current;
    int remaining;
    int visited;

    bool operator==(const State& other) const {
        return current == other.current && remaining == other.remaining && visited == other.visited;
    }
};

namespace std {
    template<> struct hash<State> {
        size_t operator()(const State& s) const {
            return ((hash<int>()(s.current) ^ (hash<int>()(s.remaining) << 1)) >> 1) ^ (hash<int>()(s.visited) << 1);
        }
    };
}

unordered_map<State, int> memo;
vector<vector<int>> dist;
vector<int> demand;
int capacity, n;

int dp(State s) {
    if (memo.count(s)) return memo[s];
    if (s.visited == (1 << n) - 1) return dist[s.current][0];

    int min_cost = INT_MAX;
    bool can_continue = false;

    for (int next = 0; next < n; ++next) {
        if (!(s.visited & (1 << next)) && demand[next] <= s.remaining) {
            State new_state = {next, s.remaining - demand[next], s.visited | (1 << next)};
            int cost = dist[s.current][next] + dp(new_state);
            min_cost = min(min_cost, cost);
            can_continue = true;
        }
    }

    if (!can_continue) {
        int return_cost = dist[s.current][0] + dp({0, capacity, s.visited});
        min_cost = min(min_cost, return_cost);
    }

    return memo[s] = min_cost;
}

int main() {
    cin >> n;
    dist.resize(n, vector<int>(n));
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            cin >> dist[i][j];

    demand.resize(n);
    for (int i = 0; i < n; ++i)
        cin >> demand[i];

    cin >> capacity;
    cout << dp({0, capacity, 0}) << endl;

    return 0;
}
