import java.util.ArrayList;
import java.util.Arrays;
import java.util.Collections;
import java.util.List;

public class TextAlignment {
    public static List<Integer> computeOptimalLineBreaks(String[] words, int maxWidth) {
        int n = words.length;
        int[] dp = new int[n + 1];
        int[] parent = new int[n + 1];
        Arrays.fill(dp, Integer.MAX_VALUE);
        dp[0] = 0;

        int[][] cost = new int[n][n];
        for (int i = 0; i < n; i++) {
            int lineLength = 0;
            for (int j = i; j < n; j++) {
                if (j > i) lineLength += 1;
                lineLength += words[j].length();
                if (lineLength > maxWidth) {
                    cost[i][j] = Integer.MAX_VALUE;
                } else {
                    cost[i][j] = (j == n - 1) ? 0 : (int) Math.pow(maxWidth - lineLength, 3);
                }
            }
        }

        for (int j = 1; j <= n; j++) {
            for (int i = 0; i < j; i++) {
                if (i < n && j - 1 < n && cost[i][j - 1] == Integer.MAX_VALUE) continue;
                if (dp[i] != Integer.MAX_VALUE && dp[j] > dp[i] + cost[i][j - 1]) {
                    dp[j] = dp[i] + cost[i][j - 1];
                    parent[j] = i;
                }
            }
        }

        List<Integer> breaks = new ArrayList<>();
        int j = n;
        while (j > 0) {
            breaks.add(j);
            j = parent[j];
        }
        Collections.reverse(breaks);
        return breaks.subList(0, breaks.size() - 1);
    }
}
