import java.util.*;

public class EvacuationPlanner {
    private List<List<Edge>> graph;
    private int V;

    public EvacuationPlanner(int nodes) {
        this.V = nodes;
        graph = new ArrayList<>(nodes);
        for (int i = 0; i < nodes; i++) {
            graph.add(new ArrayList<>());
        }
    }

    public void addEdge(int from, int to, double baseWeight, double flowRate) {
        graph.get(from).add(new Edge(to, baseWeight, flowRate));
    }

    public List<Integer> findSafestPath(int source, int destination) {
        double[][] dp = new double[V][V];
        int[][] prev = new int[V][V];
        for (int t = 0; t < V; t++) {
            Arrays.fill(dp[t], Double.POSITIVE_INFINITY);
            Arrays.fill(prev[t], -1);
        }
        dp[0][source] = 0.0;

        for (int t = 0; t < V - 1; t++) {
            for (int u = 0; u < V; u++) {
                if (dp[t][u] == Double.POSITIVE_INFINITY) continue;
                for (Edge edge : graph.get(u)) {
                    int v = edge.to;
                    double exposure = edge.baseWeight + edge.flowRate * t;
                    if (dp[t][u] + exposure < dp[t + 1][v]) {
                        dp[t + 1][v] = dp[t][u] + exposure;
                        prev[t + 1][v] = u;
                    }
                }
            }
        }

        double minExposure = Double.POSITIVE_INFINITY;
        int bestTime = -1;
        for (int t = 0; t < V; t++) {
            if (dp[t][destination] < minExposure) {
                minExposure = dp[t][destination];
                bestTime = t;
            }
        }

        if (bestTime == -1) return Collections.emptyList();

        LinkedList<Integer> path = new LinkedList<>();
        int current = destination;
        int time = bestTime;
        path.addFirst(current);
        while (time > 0) {
            current = prev[time][current];
            time--;
            path.addFirst(current);
        }

        if (current != source) return Collections.emptyList();
        return new ArrayList<>(path);
    }

    private static class Edge {
        int to;
        double baseWeight;
        double flowRate;

        Edge(int to, double baseWeight, double flowRate) {
            this.to = to;
            this.baseWeight = baseWeight;
            this.flowRate = flowRate;
        }
    }
}
