public static int knapsack(int[] values, int[] weights, int capacity) {
    int[] dp = new int[capacity + 1];
    for (int i = 0; i < values.length; i++) {
        for (int w = capacity; w >= weights[i]; w--) {
            dp[w] = Math.max(dp[w], dp[w - weights[i]] + values[i]);
        }
    }
    return dp[capacity];
}
