import java.util.*;

public class SuffixSearch {
    private List<SuffixEntry> suffixEntries = new ArrayList<>();

    public void indexDocuments(List<String> documents) {
        for (String doc : documents) {
            for (int i = 0; i < doc.length(); i++) {
                suffixEntries.add(new SuffixEntry(doc.substring(i), doc));
            }
        }
        Collections.sort(suffixEntries);
    }

    public List<String> search(String query) {
        if (query.isEmpty()) return Collections.emptyList();

        String upperBound = query + "\uffff";
        int lower = findBound(query);
        int upper = findBound(upperBound);

        Map<String, Integer> countMap = new HashMap<>();
        for (int i = lower; i < upper; i++) {
            String title = suffixEntries.get(i).documentTitle;
            countMap.put(title, countMap.getOrDefault(title, 0) + 1);
        }

        List<Map.Entry<String, Integer>> entries = new ArrayList<>(countMap.entrySet());
        entries.sort((a, b) -> {
            int cmp = b.getValue().compareTo(a.getValue());
            return cmp != 0 ? cmp : a.getKey().compareTo(b.getKey());
        });

        List<String> result = new ArrayList<>();
        for (Map.Entry<String, Integer> entry : entries) {
            result.add(entry.getKey());
        }
        return result;
    }

    private int findBound(String key) {
        int pos = Collections.binarySearch(suffixEntries, new SuffixEntry(key, ""), Comparator.comparing(a -> a.suffix));
        return pos >= 0 ? pos : -pos - 1;
    }

    private static class SuffixEntry {
        String suffix;
        String documentTitle;

        SuffixEntry(String suffix, String documentTitle) {
            this.suffix = suffix;
            this.documentTitle = documentTitle;
        }
    }

    public static void main(String[] args) {
        SuffixSearch searcher = new SuffixSearch();
        searcher.indexDocuments(Arrays.asList("apple", "application", "apply", "banana"));
        System.out.println(searcher.search("app"));
    }
}
