        self.storage_path = storage_path
        self.tree = BTree()
        if os.path.exists(self.storage_path):
            self._load()

    def insert(self, filename, metadata):
        self.tree.insert(filename, metadata)

    def delete(self, filename):
        if filename in self.tree:
            del self.tree[filename]

    def lookup(self, filename):
        return self.tree.get(filename)

    def update(self, filename, metadata):
        if filename in self.tree:
            self.tree[filename] = metadata

    def persist(self):
        with open(self.storage_path, 'wb') as f:
            pickle.dump(self.tree, f)

    def _load(self):
        with open(self.storage_path, 'rb') as f:
            self.tree = pickle.load(f)
