#include <iostream>
#include <queue>
#include <stdexcept>

using namespace std;

struct Task {
    int priority;
    int execTime;

    bool operator<(const Task& other) const {
        return priority < other.priority;
    }
};

class TaskScheduler {
private:
    priority_queue<Task> taskQueue;

public:
    void addTask(int priority, int execTime) {
        taskQueue.push({priority, execTime});
    }

    Task getNextTask() {
        if (taskQueue.empty())
            throw runtime_error("No tasks available");
        return taskQueue.top();
    }

    void removeCompletedTask() {
        if (taskQueue.empty())
            throw runtime_error("No tasks to remove");
        taskQueue.pop();
    }

    bool isEmpty() const {
        return taskQueue.empty();
    }
};

int main() {
    TaskScheduler scheduler;

    scheduler.addTask(3, 10);
    scheduler.addTask(1, 5);
    scheduler.addTask(5, 8);

    while (!scheduler.isEmpty()) {
        Task task = scheduler.getNextTask();
        cout << "Executing task with priority " << task.priority 
             << " and time " << task.execTime << endl;
        scheduler.removeCompletedTask();
    }

    return 0;
}
