#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>

typedef struct Node {
    int vertex;
    struct Node* next;
} Node;

typedef struct Edge {
    int u;
    int v;
} Edge;

int main() {
    char filename[256];
    printf("Enter filename: ");
    scanf("%255s", filename);

    FILE* file = fopen(filename, "r");
    if (!file) {
        printf("Error opening file.\n");
        return 1;
    }

    Edge* edges = NULL;
    int edgeCount = 0;
    int max_node = -1;
    int u, v;

    while (fscanf(file, "%d %d", &u, &v) == 2) {
        edges = realloc(edges, (edgeCount + 1) * sizeof(Edge));
        edges[edgeCount].u = u;
        edges[edgeCount].v = v;
        edgeCount++;
        if (u > max_node) max_node = u;
        if (v > max_node) max_node = v;
    }
    fclose(file);

    int n = max_node + 1;
    if (max_node == -1) {
        printf("No edges found.\n");
        return 1;
    }

    Node** adjList = (Node**)calloc(n, sizeof(Node*));

    for (int i = 0; i < edgeCount; ++i) {
        u = edges[i].u;
        v = edges[i].v;

        Node* newNode = (Node*)malloc(sizeof(Node));
        newNode->vertex = v;
        newNode->next = adjList[u];
        adjList[u] = newNode;

        newNode = (Node*)malloc(sizeof(Node));
        newNode->vertex = u;
        newNode->next = adjList[v];
        adjList[v] = newNode;
    }
    free(edges);

    int start, target;
    printf("Enter start and target nodes: ");
    scanf("%d %d", &start, &target);

    if (start < 0 || start >= n || target < 0 || target >= n) {
        printf("Invalid start or target node.\n");
        return 1;
    }

    bool* visited = (bool*)calloc(n, sizeof(bool));
    int* queue = (int*)malloc(n * sizeof(int));
    int front = 0, rear = 0;

    queue[rear++] = start;
    visited[start] = true;
    bool found = false;

    while (front < rear) {
        int current = queue[front++];
        if (current == target) {
            found = true;
            break;
        }
        Node* temp = adjList[current];
        while (temp) {
            int neighbor = temp->vertex;
            if (!visited[neighbor]) {
                visited[neighbor] = true;
                queue[rear++] = neighbor;
            }
            temp = temp->next;
        }
    }

    if (found) {
        printf("Connection found.\n");
    } else {
        printf("No connection.\n");
    }

    free(queue);
    free(visited);
    for (int i = 0; i < n; ++i) {
        Node* curr = adjList[i];
        while (curr) {
            Node* temp = curr;
            curr = curr->next;
            free(temp);
        }
    }
    free(adjList);

    return 0;
}
