#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef struct Node {
    int start;
    int end;
    struct Node *children[256];
    struct Node *parent;
    int suffix_index;
} Node;

char *global_text = NULL;

Node *createNode(int start, int end) {
    Node *node = malloc(sizeof(Node));
    node->start = start;
    node->end = end;
    memset(node->children, 0, sizeof(node->children));
    node->parent = NULL;
    node->suffix_index = -1;
    return node;
}

void addSuffix(Node *root, char *text, int suffix_index) {
    int n = strlen(text);
    Node *current = root;
    int i = suffix_index;

    while (i < n) {
        char c = text[i];
        if (!current->children[c]) {
            Node *leaf = createNode(i, n-1);
            leaf->suffix_index = suffix_index;
            current->children[c] = leaf;
            leaf->parent = current;
            break;
        } else {
            Node *child = current->children[c];
            int j = child->start;
            while (j <= child->end && i < n && text[j] == text[i]) {
                j++;
                i++;
            }
            if (j > child->end) {
                current = child;
            } else {
                Node *split = createNode(child->start, j-1);
                split->parent = current;
                current->children[c] = split;
                child->start = j;
                child->parent = split;
                split->children[text[j]] = child;
                Node *leaf = createNode(i, n-1);
                leaf->suffix_index = suffix_index;
                split->children[text[i]] = leaf;
                leaf->parent = split;
                break;
            }
        }
    }
}

Node *buildSuffixTree(char *text) {
    Node *root = createNode(-1, -1);
    int n = strlen(text);
    for (int i = 0; i < n; i++)
        addSuffix(root, text, i);
    return root;
}

void collectLeaves(Node *node, int *positions, int *count) {
    if (!node) return;
    if (node->suffix_index != -1) {
        positions[(*count)++] = node->suffix_index;
        return;
    }
    for (int i = 0; i < 256; i++)
        if (node->children[i])
            collectLeaves(node->children[i], positions, count);
}

void findSubstring(Node *root, char *pattern, int *positions, int *count) {
    Node *current = root;
    int i = 0, len = strlen(pattern);
    while (i < len) {
        char c = pattern[i];
        if (!current->children[c]) return;
        Node *child = current->children[c];
        int j = child->start;
        while (i < len && j <= child->end) {
            if (global_text[j] != pattern[i]) return;
            i++;
            j++;
        }
        current = child;
    }
    collectLeaves(current, positions, count);
}

int main() {
    char text[1000];
    printf("Enter the text: ");
    scanf("%999s", text);
    global_text = text;

    Node *root = buildSuffixTree(text);

    char pattern[1000];
    printf("Enter substrings to search (type 'exit' to stop):\n");
    while (1) {
        scanf("%999s", pattern);
        if (strcmp(pattern, "exit") == 0) break;

        int positions[1000], count = 0;
        findSubstring(root, pattern, positions, &count);

        if (!count) printf("Substring not found.\n");
        else {
            printf("Found at indices: ");
            for (int i = 0; i < count; i++) printf("%d ", positions[i]);
            printf("\n");
        }
    }
    return 0;
}
