#include <iostream>
#include <queue>
#include <map>
#include <string>
using namespace std;

struct Node {
    char data;
    int freq;
    Node *left, *right;
    Node(char data, int freq) : data(data), freq(freq), left(nullptr), right(nullptr) {}
    ~Node() { delete left; delete right; }
};

void generateCodes(Node* root, string code, map<char, string>& codes) {
    if (!root) return;
    if (!root->left && !root->right) {
        if (code.empty()) code = "0";
        codes[root->data] = code;
    }
    generateCodes(root->left, code + "0", codes);
    generateCodes(root->right, code + "1", codes);
}

int main() {
    string text;
    cout << "Enter the input string: ";
    getline(cin, text);

    if (text.empty()) {
        cout << "Encoded codes:\nEncoded string: \n";
        return 0;
    }

    map<char, int> freq;
    for (char c : text) freq[c]++;

    auto cmp = [](Node* left, Node* right) { return left->freq > right->freq; };
    priority_queue<Node*, vector<Node*>, decltype(cmp)> minHeap(cmp);

    for (auto& pair : freq) 
        minHeap.push(new Node(pair.first, pair.second));

    while (minHeap.size() > 1) {
        Node* left = minHeap.top(); minHeap.pop();
        Node* right = minHeap.top(); minHeap.pop();
        Node* internal = new Node('\0', left->freq + right->freq);
        internal->left = left;
        internal->right = right;
        minHeap.push(internal);
    }

    Node* root = minHeap.empty() ? nullptr : minHeap.top();
    map<char, string> codes;
    generateCodes(root, "", codes);

    string encoded;
    for (char c : text) encoded += codes[c];

    cout << "Encoded codes:\n";
    for (auto& pair : codes) 
        cout << "'" << pair.first << "' : " << pair.second << "\n";
    cout << "Encoded string: " << encoded << endl;

    delete root;
    return 0;
}
