    for (r, &c) in queens.iter().enumerate() {
        if c == col || (row as i32 - r as i32).abs() == (col as i32 - c as i32).abs() {
            return false;
        }
    }
    true
}

fn backtrack(queens: &mut Vec<u8>, row: usize, solutions: &mut Vec<Vec<u8>>) {
    if row == 8 {
        solutions.push(queens.clone());
        return;
    }
    for col in 0..8 {
        if is_safe(queens, row, col) {
            queens.push(col);
            backtrack(queens, row + 1, solutions);
            queens.pop();
        }
    }
}

