    int n;
    cin >> n;
    vector<Task> tasks(n);
    for (int i = 0; i < n; ++i) {
        tasks[i].id = i + 1;
        cin >> tasks[i].duration >> tasks[i].priority;
    }

    const int max_time = 480;
    vector<int> dp(max_time + 1, 0);
    vector<vector<bool>> selected(max_time + 1, vector<bool>(n, false));

    for (int i = 0; i < n; ++i) {
        int dur = tasks[i].duration;
        int prio = tasks[i].priority;
        for (int t = max_time; t >= dur; --t) {
            if (dp[t - dur] + prio > dp[t]) {
                dp[t] = dp[t - dur] + prio;
                selected[t] = selected[t - dur];
                selected[t][i] = true;
            }
        }
    }

    int max_prio = *max_element(dp.begin(), dp.end());
    int best_time = distance(dp.begin(), find(dp.begin(), dp.end(), max_prio));

    vector<Task> scheduled;
    for (int i = 0; i < n; ++i) {
        if (selected[best_time][i]) {
            scheduled.push_back(tasks[i]);
        }
    }

    cout << "Optimized Schedule:\n";
    cout << "Total Priority: " << max_prio << "\n";
    cout << "Total Time Used: " << best_time << " minutes\n";
