use std::cmp::Reverse;
use std::collections::BinaryHeap;

fn prim_mst(adj_list: &[Vec<(usize, i32)>]) -> Vec<(usize, usize, i32)> {
    let n = adj_list.len();
    let mut visited = vec![false; n];
    let mut heap = BinaryHeap::new();
    let mut mst_edges = Vec::new();

    heap.push(Reverse((0, 0, usize::MAX)));

    while let Some(Reverse((weight, u, parent))) = heap.pop() {
        if visited[u] {
            continue;
        }
        visited[u] = true;

        if parent != usize::MAX {
            mst_edges.push((parent, u, weight));
        }

        for &(v, w) in &adj_list[u] {
            if !visited[v] {
                heap.push(Reverse((w, v, u)));
            }
        }
    }

    mst_edges
}

fn main() {
