class BloomFilter {
    constructor(expectedItems, falsePositiveRate) {
        this.m = Math.ceil(-(expectedItems * Math.log(falsePositiveRate)) / (Math.LN2 ** 2));
        this.k = Math.ceil((this.m / expectedItems) * Math.LN2);
        this.bits = new Array(this.m).fill(0);
    }

    add(item) {
        const hashes = this._getHashes(item);
        hashes.forEach(i => this.bits[i] = 1);
    }

    check(item) {
        return this._getHashes(item).every(i => this.bits[i] === 1);
    }

    _getHashes(item) {
        const str = String(item);
        let hash1 = this._hash(str, 0x811c9dc5);
        let hash2 = this._hash(str, 0xdeadbeef);
        return Array.from({length: this.k}, (_, i) => (hash1 + i * hash2) % this.m);
    }

    _hash(str, seed) {
        let h = seed;
        for (let i = 0; i < str.length; i++) {
            h ^= str.charCodeAt(i);
            h += (h << 1) + (h << 4) + (h << 7) + (h << 8) + (h << 24);
        }
        return Math.abs(h % this.m);
    }

    getState() {
        return this.bits.join('').slice(0, 100) + '...';
    }
}

// Example usage:
const bloom = new BloomFilter(1000, 0.01);
console.log('Initial state:', bloom.getState());

bloom.add('apple');
bloom.add('banana');
bloom.add('cherry');

console.log('State after adds:', bloom.getState());
console.log('Contains "apple":', bloom.check('apple'));
console.log('Contains "grape":', bloom.check('grape'));
