struct Edge {
    int src, dest, weight;
};

void BellmanFord(struct Edge* edges, int V, int E, int src) {
    int *dist = malloc(V * sizeof(int));
    for (int i = 0; i < V; i++)
        dist[i] = INT_MAX;
    dist[src] = 0;

    for (int i = 1; i < V; i++) {
        for (int j = 0; j < E; j++) {
            int u = edges[j].src;
            int v = edges[j].dest;
            int w = edges[j].weight;
            if (dist[u] != INT_MAX && dist[u] + w < dist[v])
                dist[v] = dist[u] + w;
        }
    }

    for (int j = 0; j < E; j++) {
        int u = edges[j].src;
        int v = edges[j].dest;
        int w = edges[j].weight;
        if (dist[u] != INT_MAX && dist[u] + w < dist[v]) {
            printf("Graph contains a negative weight cycle\n");
            free(dist);
            return;
        }
    }

    for (int i = 0; i < V; i++)
        printf("%d: %d\n", i, dist[i]);
    free(dist);
}

int main() {
    int V, E, src;
    scanf("%d %d", &V, &E);
    struct Edge* edges = malloc(E * sizeof(struct Edge));
    for (int i = 0; i < E; i++)
        scanf("%d %d %d", &edges[i].src, &edges[i].dest, &edges[i].weight);
    scanf("%d", &src);
    BellmanFord(edges, V, E, src);
    free(edges);
    return 0;
}
