import java.util.Random;

public class UniversalHashTable<K, V> {
    private static final int INITIAL_CAPACITY = 11;
    private static final int PRIME = 2147483647;
    private static final double LOAD_FACTOR_THRESHOLD = 0.75;

    private Entry<K, V>[] buckets;
    private int size;
    private int capacity;
    private int a, b;
    private Random random;

    public UniversalHashTable() {
        random = new Random();
        capacity = INITIAL_CAPACITY;
        buckets = new Entry[capacity];
        generateNewHashParameters();
        size = 0;
    }

    private static class Entry<K, V> {
        K key;
        V value;
        Entry<K, V> next;

        Entry(K key, V value, Entry<K, V> next) {
            this.key = key;
            this.value = value;
            this.next = next;
        }
    }

    private void generateNewHashParameters() {
        a = random.nextInt(PRIME - 1) + 1;
        b = random.nextInt(PRIME);
    }

    private int hash(K key) {
        long hashKey = key.hashCode();
        long intermediate = (a * hashKey + b) % PRIME;
        if (intermediate < 0) intermediate += PRIME;
        return (int) (intermediate % capacity);
    }

    public void put(K key, V value) {
        if (key == null) throw new IllegalArgumentException("Key cannot be null");
        int index = hash(key);
        Entry<K, V> current = buckets[index];
        Entry<K, V> prev = null;

        while (current != null) {
            if (current.key.equals(key)) {
                current.value = value;
                return;
            }
            prev = current;
            current = current.next;
        }

        Entry<K, V> newEntry = new Entry<>(key, value, buckets[index]);
        buckets[index] = newEntry;
        size++;

        if ((double) size / capacity > LOAD_FACTOR_THRESHOLD) {
            resize();
        }
    }

    public V get(K key) {
        int index = hash(key);
        Entry<K, V> current = buckets[index];
        while (current != null) {
            if (current.key.equals(key)) return current.value;
            current = current.next;
        }
        return null;
    }

    public void delete(K key) {
        int index = hash(key);
        Entry<K, V> current = buckets[index];
        Entry<K, V> prev = null;

        while (current != null) {
            if (current.key.equals(key)) {
                if (prev == null) buckets[index] = current.next;
                else prev.next = current.next;
                size--;
                return;
            }
            prev = current;
            current = current.next;
        }
    }

    private void resize() {
        int newCapacity = nextPrime(capacity * 2);
        Entry<K, V>[] oldBuckets = buckets;
        capacity = newCapacity;
        buckets = new Entry[capacity];
        generateNewHashParameters();
        size = 0;

        for (Entry<K, V> entry : oldBuckets) {
            while (entry != null) {
                put(entry.key, entry.value);
                entry = entry.next;
            }
        }
    }

    private int nextPrime(int n) {
        while (!isPrime(n)) n++;
        return n;
    }

    private boolean isPrime(int n) {
        if (n <= 1) return false;
        if (n <= 3) return true;
        if (n % 2 == 0 || n % 3 == 0) return false;
        for (int i = 5; i * i <= n; i += 6)
            if (n % i == 0 || n % (i + 2) == 0) return false;
        return true;
    }

    public void printStatistics() {
        int usedBuckets = 0;
        int maxChainLength = 0;
        for (Entry<K, V> bucket : buckets) {
            int currentLength = 0;
            Entry<K, V> current = bucket;
            while (current != null) {
                currentLength++;
                current = current.next;
            }
            if (currentLength > 0) usedBuckets++;
            if (currentLength > maxChainLength) maxChainLength = currentLength;
        }
        System.out.println("Current Statistics:");
        System.out.println("Number of elements: " + size);
        System.out.println("Current capacity: " + capacity);
        System.out.println("Load factor: " + (double) size / capacity);
        System.out.println("Used buckets: " + usedBuckets);
        System.out.println("Longest chain length: " + maxChainLength);
    }
}
