    private int randomLevel() {
        int level = 0;
        while (rand.nextFloat() < 0.5 && level < MAX_LEVEL)
            level++;
        return level;
    }

    public boolean search(int target) {
        SkipListNode current = head;
        for (int i = currentMaxLevel; i >= 0; i--) {
            while (current.forward[i] != null && current.forward[i].value < target)
                current = current.forward[i];
        }
        current = current.forward[0];
        return current != null && current.value == target;
    }

    public void insert(int value) {
        if (search(value))
            return;
        SkipListNode[] update = new SkipListNode[MAX_LEVEL + 1];
        SkipListNode current = head;
        for (int i = currentMaxLevel; i >= 0; i--) {
            while (current.forward[i] != null && current.forward[i].value < value)
                current = current.forward[i];
            update[i] = current;
        }
        int newLevel = randomLevel();
        if (newLevel > currentMaxLevel) {
            for (int i = currentMaxLevel + 1; i <= newLevel; i++)
                update[i] = head;
            currentMaxLevel = newLevel;
        }
        SkipListNode newNode = new SkipListNode(value, newLevel);
        for (int i = 0; i <= newLevel; i++) {
            newNode.forward[i] = update[i].forward[i];
            update[i].forward[i] = newNode;
        }
    }

    public void delete(int value) {
        SkipListNode[] update = new SkipListNode[MAX_LEVEL + 1];
        SkipListNode current = head;
        for (int i = currentMaxLevel; i >= 0; i--) {
            while (current.forward[i] != null && current.forward[i].value < value)
                current = current.forward[i];
            update[i] = current;
        }
        current = current.forward[0];
        if (current == null || current.value != value)
            return;
        for (int i = 0; i <= currentMaxLevel; i++) {
            if (update[i].forward[i] != current)
                break;
            update[i].forward[i] = current.forward[i];
        }
        while (currentMaxLevel > 0 && head.forward[currentMaxLevel] == null)
            currentMaxLevel--;
    }

    public void visualize() {
        for (int i = currentMaxLevel; i >= 0; i--) {
            SkipListNode node = head.forward[i];
            System.out.print("Level " + i + ": ");
            while (node != null) {
                System.out.print(node.value + " -> ");
                node = node.forward[i];
            }
            System.out.println("null");
        }
    }
}
