function findLowestCommonAncestor(root, p, q) {
    const parentMap = new Map();
    const depthMap = new Map();
    const nodes = new Set();
    let maxDepth = 0;

    if (!root) return null;
    let queue = [root];
    parentMap.set(root, null);
    depthMap.set(root, 0);
    nodes.add(root);

    while (queue.length > 0) {
        const node = queue.shift();
        const currentDepth = depthMap.get(node);

        [node.left, node.right].forEach(child => {
            if (child) {
                parentMap.set(child, node);
                depthMap.set(child, currentDepth + 1);
                maxDepth = Math.max(maxDepth, currentDepth + 1);
                nodes.add(child);
                queue.push(child);
            }
        });
    }

    if (!nodes.has(p) || !nodes.has(q)) return null;

    const maxLevel = Math.ceil(Math.log2(maxDepth)) || 0;
    const up = new Map();

    for (const node of nodes) {
        const arr = new Array(maxLevel + 1).fill(null);
        arr[0] = parentMap.get(node);
        up.set(node, arr);
    }

    for (let k = 1; k <= maxLevel; k++) {
        for (const node of nodes) {
            const prevAncestor = up.get(node)[k - 1];
            up.get(node)[k] = prevAncestor !== null ? up.get(prevAncestor)[k - 1] : null;
        }
    }

    let u = p, v = q;

    if (depthMap.get(u) < depthMap.get(v)) [u, v] = [v, u];

    for (let k = maxLevel; k >= 0; k--) {
        const ancestor = up.get(u)[k];
        if (ancestor !== null && depthMap.get(ancestor) >= depthMap.get(v)) {
            u = ancestor;
        }
    }

    if (u === v) return u;

    for (let k = maxLevel; k >= 0; k--) {
        const uAncestor = up.get(u)[k];
        const vAncestor = up.get(v)[k];
        if (uAncestor !== vAncestor) {
            u = uAncestor;
            v = vAncestor;
        }
    }

    return parentMap.get(u);
}
