#include <iostream>
#include <string>
#include <algorithm>
#include <vector>

using namespace std;

struct SongNode {
    string title;
    string artist;
    SongNode* prev;
    SongNode* next;

    SongNode(string t, string a) : title(t), artist(a), prev(nullptr), next(nullptr) {}
};

class Playlist {
private:
    SongNode* head;
    SongNode* tail;
    SongNode* current;
    int size;

public:
    Playlist() : head(nullptr), tail(nullptr), current(nullptr), size(0) {}

    ~Playlist() {
        SongNode* temp = head;
        while (temp != nullptr) {
            SongNode* next = temp->next;
            delete temp;
            temp = next;
        }
    }

    bool addSong(string title, string artist) {
        if (size >= 50) return false;
        SongNode* newNode = new SongNode(title, artist);
        if (!head) head = tail = newNode;
        else {
            tail->next = newNode;
            newNode->prev = tail;
            tail = newNode;
        }
        size++;
        if (!current) current = head;
        return true;
    }

    bool removeSong(string title) {
        SongNode* temp = head;
        while (temp) {
            if (temp->title == title) {
                if (temp->prev) temp->prev->next = temp->next;
                else head = temp->next;
                if (temp->next) temp->next->prev = temp->prev;
                else tail = temp->prev;
                if (current == temp) current = temp->next ? temp->next : temp->prev;
                delete temp;
                size--;
                return true;
            }
            temp = temp->next;
        }
        return false;
    }

    void displayPlaylist() {
        SongNode* temp = head;
        while (temp) {
            cout << "Title: " << temp->title << ", Artist: " << temp->artist << endl;
            temp = temp->next;
        }
    }

    void goNext() {
        if (current && current->next) current = current->next;
    }

    void goPrevious() {
        if (current && current->prev) current = current->prev;
    }

    void showCurrent() {
        if (current) cout << "Current Song: " << current->title << " by " << current->artist << endl;
        else cout << "No current song." << endl;
    }

    void sortSongs() {
        if (size <= 1) return;
        vector<SongNode*> nodes;
        SongNode* temp = head;
        while (temp) {
            nodes.push_back(temp);
            temp = temp->next;
        }
        sort(nodes.begin(), nodes.end(), [](SongNode* a, SongNode* b) { return a->title < b->title; });
        head = nodes[0];
        head->prev = nullptr;
        for (int i = 1; i < nodes.size(); ++i) {
            nodes[i-1]->next = nodes[i];
            nodes[i]->prev = nodes[i-1];
        }
        tail = nodes.back();
        tail->next = nullptr;
        current = head;
    }
};

int main() {
    Playlist playlist;
    int choice;
    string title, artist;

    do {
        cout << "\nPlaylist Manager\n1. Add Song\n2. Remove Song\n3. Display Playlist\n4. Next Song\n5. Previous Song\n6. Show Current Song\n7. Sort Playlist\n8. Exit\nEnter choice: ";
        cin >> choice;
        cin.ignore();
        switch (choice) {
            case 1:
                cout << "Enter song title: ";
                getline(cin, title);
                cout << "Enter artist: ";
                getline(cin, artist);
                if (!playlist.addSong(title, artist)) cout << "Playlist is full (max 50 songs).\n";
                break;
            case 2:
                cout << "Enter song title to remove: ";
                getline(cin, title);
                if (!playlist.removeSong(title)) cout << "Song not found.\n";
                break;
            case 3:
                playlist.displayPlaylist();
                break;
            case 4:
                playlist.goNext();
                break;
            case 5:
                playlist.goPrevious();
                break;
            case 6:
                playlist.showCurrent();
                break;
            case 7:
                playlist.sortSongs();
                break;
            case 8:
                cout << "Exiting...\n";
                break;
            default:
                cout << "Invalid choice.\n";
        }
    } while (choice != 8);

    return 0;
}
