use std::cell::Cell;

pub struct UnionFind {
    parent: Vec<Cell<usize>>,
    rank: Vec<Cell<usize>>,
}

impl UnionFind {
    pub fn new(size: usize) -> Self {
        let parent = (0..size).map(|i| Cell::new(i)).collect();
        let rank = vec![Cell::new(0); size];
        UnionFind { parent, rank }
    }

    pub fn find(&self, x: usize) -> usize {
        let mut root = x;
        while self.parent[root].get() != root {
            root = self.parent[root].get();
        }
        let mut current = x;
        while self.parent[current].get() != root {
            let next_parent = self.parent[current].get();
            self.parent[current].set(root);
            current = next_parent;
        }
        root
    }

    pub fn union(&self, x: usize, y: usize) {
        let root_x = self.find(x);
        let root_y = self.find(y);
        if root_x != root_y {
            let rank_x = self.rank[root_x].get();
            let rank_y = self.rank[root_y].get();
            if rank_x < rank_y {
                self.parent[root_x].set(root_y);
            } else {
                self.parent[root_y].set(root_x);
                if rank_x == rank_y {
                    self.rank[root_x].set(rank_x + 1);
                }
            }
        }
    }

    pub fn is_connected(&self, x: usize, y: usize) -> bool {
        self.find(x) == self.find(y)
    }
}
