#include <iostream>
#include <stack>
#include <string>
#include <sstream>
#include <stdexcept>

using namespace std;

bool is_number(const string& s) {
    try {
        size_t pos;
        stod(s, &pos);
        if (pos != s.size()) return false;
    } catch (const exception&) {
        return false;
    }
    return true;
}

bool is_operator(const string& s) {
    return s == "+" || s == "-" || s == "*" || s == "/";
}

int main() {
    string expr;
    getline(cin, expr);
    istringstream iss(expr);
    stack<double> st;
    string token;
    bool error = false;

    while (iss >> token && !error) {
        if (is_number(token)) {
            st.push(stod(token));
        } else if (is_operator(token)) {
            if (st.size() < 2) {
                cerr << "Error: Insufficient operands\n";
                error = true;
                break;
            }
            double b = st.top(); st.pop();
            double a = st.top(); st.pop();
            if (token == "+") st.push(a + b);
            else if (token == "-") st.push(a - b);
            else if (token == "*") st.push(a * b);
            else if (token == "/") {
                if (b == 0) {
                    cerr << "Error: Division by zero\n";
                    error = true;
                    break;
                }
                st.push(a / b);
            }
        } else {
            cerr << "Error: Invalid token\n";
            error = true;
            break;
        }
    }

    if (!error && st.size() != 1) {
        cerr << "Error: Invalid expression format\n";
        error = true;
    }

    if (!error) cout << st.top() << endl;
    return error ? 1 : 0;
}
