import java.util.Collections;
import java.util.TreeMap;

public class RunningMedian {
    private TreeMap<Integer, Integer> lower = new TreeMap<>(Collections.reverseOrder());
    private TreeMap<Integer, Integer> higher = new TreeMap<>();
    private int lowerSize = 0;
    private int higherSize = 0;

    public void add(int num) {
        if (lower.isEmpty() || num <= lower.firstKey()) {
            lower.put(num, lower.getOrDefault(num, 0) + 1);
            lowerSize++;
        } else {
            higher.put(num, higher.getOrDefault(num, 0) + 1);
            higherSize++;
        }
        balance();
    }

    public void remove(int num) {
        if (lower.containsKey(num)) {
            int count = lower.get(num);
            if (count == 1) {
                lower.remove(num);
            } else {
                lower.put(num, count - 1);
            }
            lowerSize--;
        } else if (higher.containsKey(num)) {
            int count = higher.get(num);
            if (count == 1) {
                higher.remove(num);
            } else {
                higher.put(num, count - 1);
            }
            higherSize--;
        }
        balance();
    }

    private void balance() {
        while (lowerSize > higherSize + 1) {
            int key = lower.firstKey();
            lower.put(key, lower.get(key) - 1);
            if (lower.get(key) == 0) lower.remove(key);
            lowerSize--;
            higher.put(key, higher.getOrDefault(key, 0) + 1);
            higherSize++;
        }
        while (higherSize > lowerSize) {
            int key = higher.firstKey();
            higher.put(key, higher.get(key) - 1);
            if (higher.get(key) == 0) higher.remove(key);
            higherSize--;
            lower.put(key, lower.getOrDefault(key, 0) + 1);
            lowerSize++;
        }
    }

    public double getMedian() {
        if (lowerSize + higherSize == 0) throw new IllegalStateException("No elements present");
        return (lowerSize > higherSize) ? lower.firstKey() : (lower.firstKey() + higher.firstKey()) / 2.0;
    }
}
