use std::i64;

struct Edge {
    from: usize,
    to: usize,
    weight: i64,
}

struct Graph {
    edges: Vec<Edge>,
}

impl Graph {
    fn new() -> Self {
        Graph { edges: Vec::new() }
    }

    fn add_edge(&mut self, from: usize, to: usize, weight: i64) {
        self.edges.push(Edge { from, to, weight });
    }
}

fn bellman_ford(graph: &Graph, num_nodes: usize, source: usize) -> (Vec<i64>, bool) {
    let mut distances = vec![i64::MAX; num_nodes];
    distances[source] = 0;

    for _ in 0..num_nodes - 1 {
        for edge in &graph.edges {
            if distances[edge.from] != i64::MAX {
                let new_distance = distances[edge.from] + edge.weight;
                if new_distance < distances[edge.to] {
                    distances[edge.to] = new_distance;
                }
            }
        }
    }

    let mut has_negative_cycle = false;
    for edge in &graph.edges {
        if distances[edge.from] != i64::MAX {
            let new_distance = distances[edge.from] + edge.weight;
            if new_distance < distances[edge.to] {
                has_negative_cycle = true;
                break;
            }
        }
    }

    (distances, has_negative_cycle)
}

fn main() {
    let mut graph = Graph::new();
    graph.add_edge(0, 1, 4);
    graph.add_edge(1, 2, -3);
    graph.add_edge(2, 3, 2);
    graph.add_edge(3, 1, -1);

    let source = 0;
    let num_nodes = 4;
    let (distances, has_negative_cycle) = bellman_ford(&graph, num_nodes, source);

    if has_negative_cycle {
        println!("Negative weight cycle detected!");
    } else {
        println!("Shortest travel times from station {}:", source);
        for (i, &time) in distances.iter().enumerate() {
            if time == i64::MAX {
                println!("Station {}: unreachable", i);
            } else {
                println!("Station {}: {}", i, time);
            }
        }
    }
}
