class Graph {
    constructor(vertices) {
        this.V = vertices;
        this.adj = new Array(vertices).fill().map(() => []);
    }

    addEdge(u, v, weight) {
        this.adj[u].push([v, weight]);
        this.adj[v].push([u, weight]);
    }
}

function primMST(graph) {
    const key = new Array(graph.V).fill(Infinity);
    const inMST = new Array(graph.V).fill(false);
    key[0] = 0;

    for (let count = 0; count < graph.V - 1; count++) {
        const u = minKey(key, inMST);
        inMST[u] = true;

        for (const [v, weight] of graph.adj[u]) {
            if (!inMST[v] && weight < key[v]) {
                key[v] = weight;
            }
        }
    }

    return key.reduce((a, b) => a + b, 0);
}

function minKey(key, inMST) {
    let min = Infinity;
    let minIndex = -1;
    for (let v = 0; v < key.length; v++) {
        if (!inMST[v] && key[v] < min) {
            min = key[v];
            minIndex = v;
        }
    }
    return minIndex;
}

