function generateFitnessPlan(exercises) {
    const weeklyPlan = [];
    const dailyLimit = 60;
    for (let day = 1; day <= 7; day++) {
        let remaining = dailyLimit;
        const dailyExercises = [];
        let totalCalories = 0;
        const sorted = [...exercises].sort((a, b) => (b.calories / b.duration) - (a.calories / a.duration));
        for (const exercise of sorted) {
